function simulateUpload(file, onProgress) {
  return new Promise((resolve) => {
    let progress2 = 0;
    const tick = () => {
      progress2 += Math.random() * 18 + 8;
      if (progress2 >= 100) {
        onProgress(100);
        resolve(URL.createObjectURL(file));
      } else {
        onProgress(Math.min(progress2, 95));
        setTimeout(tick, 120);
      }
    };
    setTimeout(tick, 120);
  });
}
